"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[73402],{89799:e=>{e.exports=JSON.parse('{"tag":{"label":"debuff","permalink":"/dst-api-webdocs/docs/tags/debuff","allTagsPath":"/dst-api-webdocs/docs/tags","count":20,"items":[{"id":"game-scripts/prefabs/ancienttree_fruits","title":"Ancienttree Fruits","description":"Provides game logic for ancient tree fruits, including gem fruit temperature-based hatching, night vision fruit effects, and the night vision debuff component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttree_fruits"},{"id":"game-scripts/prefabs/compostwrap","title":"Compostwrap","description":"A reusable item that applies slow fertilizer effect and provides minor health regeneration when equipped as a debuff on living targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/compostwrap"},{"id":"game-scripts/components/cursable","title":"Cursable","description":"Manages application, removal, and state tracking of curses on an entity, primarily by interacting with cursed items and inventory.","permalink":"/dst-api-webdocs/docs/game-scripts/components/cursable"},{"id":"game-scripts/prefabs/firenettles","title":"Firenettles","description":"A consumable vegetable item that applies a temporary temperature-based debuff to non-plantkin eaters, which can be dried to produce a longer-lasting fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firenettles"},{"id":"game-scripts/prefabs/gelblob_attach_fx","title":"Gelblob Attach Fx","description":"Manages the visual attachment effect and debuff application when a gel blob connects to a player or creature.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gelblob_attach_fx"},{"id":"game-scripts/prefabs/ghostly_elixirs","title":"Ghostly Elixirs","description":"Creates consumable ghostly elixir items and their associated debuff components that apply temporary buffs to targets upon use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostly_elixirs"},{"id":"game-scripts/prefabs/healingsalve","title":"Healingsalve","description":"Provides healing functionality and implements a debuff-based acid immunity buff system for player or entity use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/healingsalve"},{"id":"game-scripts/components/inkable","title":"Inkable","description":"Tracks and manages temporary ink status on players affected by squid attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inkable"},{"id":"game-scripts/prefabs/ipecacsyrup","title":"Ipecacsyrup","description":"A consumable item that applies a debuff causing periodic poison damage and poop spawning over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ipecacsyrup"},{"id":"game-scripts/prefabs/mermking_gear_buffs","title":"Mermking Gear Buffs","description":"Provides prefab factory functions to generate temporary debuff components for Merm King gear upgrades (Trident, Crown, Pauldron) that modify combat stats of attached targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermking_gear_buffs"},{"id":"game-scripts/prefabs/miasmadebuff","title":"Miasmadebuff","description":"A non-networked server-side debuff that periodically damages targets lacking Miasma immunity, stopping when the target dies or becomes immune.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/miasmadebuff"},{"id":"game-scripts/components/miasmawatcher","title":"MiasmaWatcher","description":"Tracks whether an entity is inside a miasma cloud and applies movement speed penalties accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/miasmawatcher"},{"id":"game-scripts/prefabs/mindcontroller","title":"Mindcontroller","description":"A classified entity component that tracks and manages mind control progression and duration for a target entity, primarily used by the Stalker\'s mind control mechanic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mindcontroller"},{"id":"game-scripts/prefabs/purebrilliance","title":"Purebrilliance","description":"A consumable item that casts a wurt lunar spell, applying debuffs and triggering cheer events on nearby lunar minion followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/purebrilliance"},{"id":"game-scripts/prefabs/shadow_beef_bell_curse","title":"Shadow Beef Bell Curse","description":"Applies health and sanity penalties to a target entity when attached and detached, and spawns a visual effect during its duration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_beef_bell_curse"},{"id":"game-scripts/prefabs/shadow_trap","title":"Shadow Trap","description":"A trap prefab that detects nearby panic-capable targets, triggers a shockwave effect, and applies a movement speed penalty and panic state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_trap"},{"id":"game-scripts/prefabs/slingshotammo_debuffs","title":"Slingshotammo Debuffs","description":"Defines slingshot ammo-specific debuff prefabs and their logic, including planar damage application, visual effects, and flash animation handling for debuffs like Pure Brilliance, Horror Fuel, and Slow.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotammo_debuffs"},{"id":"game-scripts/prefabs/sporebomb","title":"Sporebomb","description":"Applies a debuff that follows a target, fades out over time, and spawns a spore cloud upon detachment or timer expiration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sporebomb"},{"id":"game-scripts/prefabs/tillweedsalve","title":"Tillweedsalve","description":"A consumable healing item that applies a debuff-based regenerative effect to living targets over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tillweedsalve"},{"id":"game-scripts/prefabs/wormwood_vined_debuff","title":"Wormwood Vined Debuff","description":"Applies a rooted debuff effect to a target entity, dealing periodic damage and attaching a visual FX entity that follows a specific symbol on the target.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormwood_vined_debuff"}],"unlisted":false}}')}}]);